UPDATE approval_outbox SET publish_status='RETRY', retry_count=retry_count+1,
next_retry_at=#{nextRetryAt}, last_error=#{lastError},
updated_at=CURRENT_TIMESTAMP WHERE id=#{id}

UPDATE approval_outbox SET publish_status='RETRY', next_retry_at=CURRENT_TIMESTAMP,
last_error='STALE_PUBLISHING_RECOVERED', updated_at=CURRENT_TIMESTAMP
WHERE publish_status='PUBLISHING' AND updated_at < #{cutoff}
